SELECT t.*, ste.site_nm AS site_nm, cd_tt.code_label AS template_type_cd_nm FROM sy_template t LEFT JOIN sy_site ste ON ste.site_id = t.site_id LEFT JOIN sy_code cd_tt ON cd_tt.code_grp = 'TEMPLATE_TYPE' AND cd_tt.code_value = t.template_type_cd
ORDER BY t.template_id ASC ORDER BY t.template_id DESC ORDER BY t.template_nm ASC ORDER BY t.template_nm DESC ORDER BY t.reg_date ASC ORDER BY t.reg_date DESC ORDER BY t.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

