site_id = #{siteId}, template_type_cd = #{templateTypeCd}, template_code = #{templateCode}, template_nm = #{templateNm}, template_subject = #{templateSubject}, template_content = #{templateContent}, sample_params = #{sampleParams}, use_yn = #{useYn}, upd_by = #{updBy}, upd_date = #{updDate}, disp_path = #{dispPath},
WHERE template_id = #{templateId}
